/* greenboost_cuda.map — GNU ld version script (NixOS override)
 *
 * NixOS packages (llama-cpp, ollama) are built against CUDA 12.x and use
 * ELF symbol versioning with libcudart.so.12:
 *
 *   cudaMalloc@libcudart.so.12
 *   cudaFree@libcudart.so.12
 *   cudaMemGetInfo@libcudart.so.12
 *   cudaMallocManaged@libcudart.so.12
 *   cudaMallocAsync@libcudart.so.12
 *   dlopen@GLIBC_2.34
 *   dlsym@GLIBC_2.34
 *
 * Unversioned exports from LD_PRELOAD do NOT satisfy versioned requirements.
 * We must export our hooks under the exact version strings callers require.
 *
 * Exporting dlopen@@GLIBC_2.2.5 lets us strip RTLD_DEEPBIND before any
 * CUDA plugin (libggml-cuda.so etc.) is loaded — RTLD_DEEPBIND causes the
 * plugin to resolve cudaMalloc from its bundled libcudart (local scope),
 * bypassing our hooks.
 *
 * Exporting dlsym@@GLIBC_2.2.5 lets us intercept GPU memory discovery
 * calls (cuDeviceTotalMem_v2, nvmlDeviceGetMemoryInfo, etc.) to report
 * the inflated virtual VRAM size.
 *
 * Upstream ships libcudart.so.13 (targeting non-NixOS CUDA 13 installs).
 * This file overrides it for NixOS where nixpkgs CUDA 12.x is standard.
 */

libcudart.so.12 {
    global:
        cudaMalloc;
        cudaMallocAsync;
        cudaFree;
        cudaMallocManaged;
};

GLIBC_2.34 {
    global:
        dlopen;
        dlsym;
};
